import{_ as a,H as i,f as t,i as o}from"./chunks/framework.DbTCwA-u.js";const p=JSON.parse('{"title":"Instalación y Requisitos","description":"Aprende cómo instalar EligiusNametag en tu servidor Paper o Folia.","frontmatter":{"title":"Instalación y Requisitos","description":"Aprende cómo instalar EligiusNametag en tu servidor Paper o Folia."},"headers":[],"relativePath":"es/installation.md","filePath":"es/installation.md"}'),s={name:"es/installation.md"};function n(r,e,l,d,c,u){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="instalacion-y-requisitos" tabindex="-1">Instalación y Requisitos <a class="header-anchor" href="#instalacion-y-requisitos" aria-label="Permalink to &quot;Instalación y Requisitos&quot;">​</a></h1><p>EligiusNametag es un plugin moderno y potente. Al aprovechar las últimas características de la API de texto de Minecraft y el sistema de subprocesos múltiples, requiere un entorno actualizado.</p><h2 id="📋-requisitos-del-sistema" tabindex="-1">📋 Requisitos del Sistema <a class="header-anchor" href="#📋-requisitos-del-sistema" aria-label="Permalink to &quot;📋 Requisitos del Sistema&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Versión Mínima</th><th>Razón</th></tr></thead><tbody><tr><td><strong>Plataforma</strong></td><td>Paper 1.21 o Folia 1.21+</td><td>Uso estricto de componentes <code>TEXT_DISPLAY</code> y comandos Brigadier.</td></tr><tr><td><strong>Java</strong></td><td>Java 21 LTS</td><td>Código fuente compilado en formato JDK 21.</td></tr></tbody></table><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><p>Debes tener instalados los siguientes plugins en tu carpeta <code>plugins/</code>:</p><ol><li><strong>ProtocolLib</strong> <em>(Obligatorio)</em>: Utilizado para enviar los paquetes de hologramas de manera invisible y sin consumo de TPS físicos.</li><li><strong>Vault</strong> <em>(Opcional)</em>: Si deseas otorgar diseños de nametag específicos dependiendo del rango del usuario (Admin, VIP, etc.).</li><li><strong>PlaceholderAPI</strong> <em>(Opcional)</em>: Para parsear variables externas como estadísticas, dinero o clanes en los nametags.</li><li><strong>ItemsAdder</strong> <em>(Opcional)</em>: Para mostrar emojis personalizados en los nombres.</li></ol><h2 id="🚀-pasos-de-instalacion" tabindex="-1">🚀 Pasos de Instalación <a class="header-anchor" href="#🚀-pasos-de-instalacion" aria-label="Permalink to &quot;🚀 Pasos de Instalación&quot;">​</a></h2><ol><li>Descarga el archivo <code>EligiusNametag-1.x.x.jar</code> desde la pestaña <strong>Releases</strong>.</li><li>Copia el archivo en el directorio <code>plugins/</code> de tu servidor.</li><li>Asegúrate de tener <strong>ProtocolLib</strong> instalado.</li><li>Inicia tu servidor.</li><li>Verás en la consola la animación de inicio con el gato de Eligius MC confirmando que el plugin se ha conectado.</li><li>¡Listo! Puedes configurar todo desde <code>plugins/EligiusNametag/</code>.</li></ol>',9)])])}const g=a(s,[["render",n]]);export{p as __pageData,g as default};
